#!/bin/bash
set -e
cd ~/Downloads/Mishwar
echo "▼ Replacing App.jsx with public-routes version..."
echo "" | base64 -d > src/App.jsx
LINES=$(wc -l < src/App.jsx)
echo "✓ App.jsx written ($LINES lines)"
if grep -q "PUBLIC_PATHS" src/App.jsx; then
  echo "✓ PUBLIC_PATHS confirmed in App.jsx"
else
  echo "✗ ERROR: PUBLIC_PATHS not found — file write failed"
  exit 1
fi

echo ""
echo "▼ Verifying syntax with local build..."
if [ ! -d node_modules ]; then
  echo "  Installing dependencies first (one-time)..."
  npm install --silent 2>&1 | tail -3
fi
npm run build 2>&1 | tail -8

echo ""
echo "▼ Committing and pushing..."
git add src/App.jsx
git commit -m "Fix: home page is now public — / no longer redirects to /login"
git push origin main
echo ""
echo "✅ Done. Wait ~30s for Vercel to redeploy, then visit https://mishwar-nu.vercel.app/"
